const authenApi = "https://taynguyen1.weathervietnam.vn/api/v3/account";
const stationApi = "https://taynguyen1.weathervietnam.vn//api/v3/backend";

const TOKEN_KEY = 'aiJwt';

const HEADERS = {
  DEFAULT_HEADER: { "Content-Type": "application/json; charset=UTF-8" },
  JWT_HEADER: () => ({
    "Content-Type": "application/json; charset=UTF-8",
    Authorization: localStorage.getItem(TOKEN_KEY),
    accept: "application/json",
  }),
};

export const auth = {
  isLoggedIn: () => !!localStorage.getItem(TOKEN_KEY),
  removeToken: () => localStorage.removeItem(TOKEN_KEY),

  login: async (user_name, user_pass) => {
    const res = await fetch(authenApi + "/login", {
      method: "POST",
      headers: HEADERS.DEFAULT_HEADER,
      body: JSON.stringify({ username: user_name, password: user_pass  }),
    });

    const text = await res.text();
    console.log("Login response status:", res.status);
    console.log("Login response body:", text);
    let data = {};
    try { data = JSON.parse(text); } catch (_) {}

    if (!res.ok) {
      throw new Error(data.message || data.detail || "Sai tài khoản hoặc mật khẩu");
    }

    // ✅ Đúng theo code cũ: response.data.data chứa payload
    // axios bọc thêm 1 lớp .data, nên server thực trả: { data: { token/access_token: ... } }
    const payload = data.data ?? data;

    const token =
      payload.access_token ||
      payload.token ||
      payload.aiJwt;

    if (!token) throw new Error("Không nhận được token từ server");

    // Code cũ lưu raw token, KHÔNG có "Bearer " prefix
    // JWT_HEADER dùng thẳng giá trị từ localStorage làm Authorization
    localStorage.setItem(TOKEN_KEY, token);
    return token;
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY);
    window.location.reload();
  },
};

export const API = {
  AUTH: {
    login: () => ({
      endPoint: authenApi + "/login",
      method: "POST",
      headers: HEADERS.DEFAULT_HEADER,
    }),
    loginWithToken: () => ({
      endPoint: authenApi + "/login/token",
      method: "POST",
      headers: HEADERS.JWT_HEADER(),
    }),
  },

  TRUNGBO: {
    getAll: () => ({
      endPoint: stationApi + "/trungbo-aws-config/",
      method: "GET",
      headers: HEADERS.JWT_HEADER(),
    }),
    getById: (id) => ({
      endPoint: stationApi + `/trungbo-aws-config/${id}`,
      method: "GET",
      headers: HEADERS.JWT_HEADER(),
    }),
    create: () => ({
      endPoint: stationApi + "/trungbo-aws-config/",
      method: "POST",
      headers: HEADERS.JWT_HEADER(),
    }),
    update: (id) => ({
      endPoint: stationApi + `/trungbo-aws-config/${id}`,
      method: "PUT",
      headers: HEADERS.JWT_HEADER(),
    }),
    delete: (id) => ({
      endPoint: stationApi + `/trungbo-aws-config/${id}`,
      method: "DELETE",
      headers: HEADERS.JWT_HEADER(),
    }),
  },
};

export async function callApi({ endPoint, method, headers }, body = null) {
  const options = { method, headers };
  if (body) options.body = JSON.stringify(body);

  const res = await fetch(endPoint, options);

  if (res.status === 401) {
    auth.removeToken();
    window.location.reload();
    return;
  }

  const text = await res.text();
  let data = {};
  try { data = JSON.parse(text); } catch (_) {}

  if (!res.ok) throw new Error(data.message || data.detail || `Lỗi ${res.status}`);
  return data;
}
